BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?req ?name WHERE {
  VALUES ?pkg {
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::APS::Black%2520Box%2520Specification::Requirements::04%2520APS%2520L3%2520Requirements::L3%2520APT%2520Requirements>
  }
  ?pkg vocab:Element_ownedElement ?req .
  ?req rdf:type vocab:tmt%20requirement .
  ?req vocab:NamedElement_name ?name .
}
LIMIT 100

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?req ?name WHERE {
  ?req rdf:type vocab:tmt%20requirement .
  ?req vocab:NamedElement_name ?name .
  ?req vocab:NamedElement_qualifiedName ?qname .
  FILTER(CONTAINS(STR(?qname), "APS") && CONTAINS(STR(?qname), "L3") && CONTAINS(STR(?qname), "APT"))

  # Check that there is NO satisfy or verify link
  FILTER NOT EXISTS {
    ?dep rdf:type vocab:satisfy .
    ?dep vocab:Dependency_client ?req .
  }
  FILTER NOT EXISTS {
    ?dep rdf:type vocab:verify .
    ?dep vocab:Dependency_client ?req .
  }
}
LIMIT 100
